def correct_data_from_redis(self, **kwargs):
    r = redis.StrictRedis(host=settings.REDIS_HOST, port=6380)

    # Get and remove the leftmost item from the list (FIFO)
    data = r.lpop("sensors.correct_data")

    if data:
        try:
            # Parse the JSON data
            sensor_data = json.loads(data)

            # Extract the required fields
            sensor_id = sensor_data["sensor_id"]
            date_begin = sensor_data["date_begin"]
            date_end = sensor_data["date_end"]

            # Process the data by calling correct_data_for_sensor
            correct_data_for_sensor.delay(
                sensor_id=sensor_id, date_begin=date_begin, date_end=date_end
            )

        except (json.JSONDecodeError, KeyError) as e:
            logger.error(f"Error processing Redis data: {e}")
            # Optionally handle the error (e.g., move to error queue)

        except Exception as e:
            logger.error(f"Unexpected error processing Redis data: {e}")


